class Solution:
    def tree2str(self, root):
        if root is None:
            return ''
        parts = [str(root.val)]
        if root.left is not None or root.right is not None:
            parts.append('(' + self.tree2str(root.left) + ')')
        if root.right is not None:
            parts.append('(' + self.tree2str(root.right) + ')')
        return ''.join(parts)

