class Solution:
    def tree2str(self, root):
        def build(node):
            if node is None:
                return ''
            s = str(node.val)
            if node.left is None and node.right is None:
                return s
            s += '(' + build(node.left) + ')'
            if node.right is not None:
                s += '(' + build(node.right) + ')'
            return s
        return build(root)

