var tree2str = function(root) {
    const build = (node) => {
        if (node === null) return '';
        let s = String(node.val);
        if (node.left === null && node.right === null) return s;
        s += '(' + build(node.left) + ')';
        if (node.right !== null) s += '(' + build(node.right) + ')';
        return s;
    };
    return build(root);
};
